parameters.jsCode:
const raw = $input.first().json.candidates?.[0]?.content?.parts?.[0]?.text;
if (!raw) {
  return [{ json: { error: 'No content from Gemini', raw: $input.first().json } }];
}
try {
  const parsed = JSON.parse(raw);
  parsed.source_url = $('Extract URL').first().json.source_url;
  parsed.analyzed_at = new Date().toISOString();
  return [{ json: { ...parsed, chat_id: $('Extract URL').first().json.chat_id, formatted: '```json\n' + JSON.stringify(parsed, null, 2) + '\n```' } }];
} catch (e) {
  return [{ json: { error: 'Invalid JSON from Gemini', raw, chat_id: $('Extract URL').first().json.chat_id } }];
}

